#include <stdio.h>

void doubleValue(int x) {
  x = x * 2;
  printf("Inside function: %d\n", x);
}

void doubleRef(int *x) {
  *x = *x * 2;
}

int main() {
  int num = 5;
  doubleValue(num);
  printf("After call by value: %d\n", num);
  doubleRef(&num);
  printf("After call by reference: %d\n", num);
  return 0;
}
